insert into vm_authview_member_auth ( id, state, start_member_id, start_date, approve_member_id, approve_date, finishedflag, ratifyflag, ratify_member_id, ratify_date, sort, modify_member_id, modify_date, memberName, memberCode, authObjName, authObjType, memberId, authObjId, memberState, authObjCode, updateTime, extendStr )
select util_common.getAbsID() as id,1,-6760911671874597139,sysdate,0,sysdate,0,0,0,null,0,-6760911671874597139,sysdate, member_name as membername, util_user.getMemCodeByMemId(member_id) as membercode, object_name as authObjName, object_type as authObjType, object_id as authObjId, member_id as memberId, (select is_enable from org_member where id = member_id) as memberState, object_code authObjCode, update_time as updateTime, extendStr
from table(util_user.getAllUserRightObjects())
